from agent import *from models.products import *def run(context, session):    session.queue(Request('https://www.sega-mag.com/tests'), process_revlist, dict())def process_revlist(data, context, session):    revs = data.xpath('//div[@class="list items--separator--border"]//div[@class="teaser__content"]')    for rev in revs:        name = rev.xpath('h2/a/span/text()').string()        url = rev.xpath('h2/a/@href').string()        date = rev.xpath('span[@class="date"]/text()').string()        author = rev.xpath('.//a[@class="username"]').first()        session.queue(Request(url), process_review, dict(name=name, url=url, date=date, author=author))    next_page = data.xpath('//a[@rel="next"]/@href').string()    if next_page:        session.queue(Request(next_page), process_revlist, dict())def process_review(data, context, session):    product = Product()    product.url = context['url']    product.ssid = context['url'].split('-')[-1]    product.name = context['name'].replace('Test : ', '').split(' (')[0]    product.category = 'Games'    if '(' in context['name']:        product.category += '|' + context['name'].split(' (')[-1].replace(')', '')    review = Review()    review.type = 'pro'    review.title = context['name']    review.url = context['url']    review.date = context['date']    review.ssid = product.ssid    author = context.get("author")    if author:        name = author.xpath("text()").string()        url = author.xpath("@href").string()        review.authors.append(Person(name=name, ssid=name, profile_url=url))    grade = data.xpath("//div[contains(@class,'test-note')]//text()").string()    if grade:        review.grades.append(Grade(type='overall', value=float(grade), best=10.0))    pros = data.xpath("//h4[contains(.,'Points forts')]/following-sibling::div//li")    for pro in pros:        pro = pro.xpath(".//text()").string()        review.add_property(type="pros", value=pro)    cons = data.xpath("//h4[contains(.,'Points faibles')]/following-sibling::div//li")    for con in cons:        con = con.xpath(".//text()").string()        review.add_property(type="cons", value=con)    summary = data.xpath("//div[@class='block__content']//p[1]//i//text()").string(multiple=True)    if not summary:        summary = data.xpath("//div[@class='block__content']/div/b[1]/text()").string(multiple=True)    if summary:        review.add_property(type='summary', value=summary)    conclusion = data.xpath("//div[@class='block__content']//p/b[last()]/text()").string(multiple=True)    if conclusion:        review.add_property(type='conclusion', value=conclusion)    excerpt = data.xpath("//div[@class='block__content']/div/text()").string(multiple=True)    if not excerpt:        excerpt = data.xpath("//div[contains(@class,  'block--field-block:node:test:body')]//div[@class='block__content']//p//text()").string(multiple=True)    if excerpt:        excerpt = excerpt.replace("''", "'")        if summary:            excerpt = excerpt.replace(summary.strip(), '')        if conclusion:            excerpt = excerpt.replace(conclusion.strip(), '')        excerpt = excerpt.strip()        if excerpt:            review.add_property(type='excerpt', value=excerpt)            product.reviews.append(review)            session.emit(product)